"""BaseContext generic abstract base class.

Every context module inherits from ``BaseContext[T]`` and implements ``format()``
to produce a list of ``ContextItem`` instances for the context assembly pipeline.
"""

from __future__ import annotations

from abc import ABC, abstractmethod
from typing import Generic, TypeVar

from core.context.types import ContextItem

T = TypeVar("T")


class BaseContext(ABC, Generic[T]):
    """Generic base providing standard CRUD operations on stored items."""

    def __init__(self) -> None:
        self._items: list[T] = []

    def add(self, item: T) -> None:
        self._items.append(item)

    def get(self, index: int) -> T | None:
        if 0 <= index < len(self._items):
            return self._items[index]
        return None

    def get_all(self) -> list[T]:
        return list(self._items)

    def clear(self) -> None:
        self._items.clear()

    def remove_last(self) -> T | None:
        if self._items:
            return self._items.pop()
        return None

    def replace(self, items: list[T]) -> None:
        self._items = list(items)

    def slice(self, start: int, end: int | None = None) -> list[T]:
        return self._items[start:end]

    def count(self) -> int:
        return len(self._items)

    def is_empty(self) -> bool:
        return len(self._items) == 0

    @abstractmethod
    def format(self) -> list[ContextItem]:
        """Subclasses convert stored items into a list of ContextItems."""
        ...

"""ReadFile 工具的执行逻辑与输出格式化。"""

from __future__ import annotations

import os
from dataclasses import dataclass
from typing import Any

from core.tool.types import ToolResult

MAX_OUTPUT_CHARS = 100_000


@dataclass
class ReadFileData:
    content: str
    file_path: str
    total_lines: int
    lines_read: int
    offset: int


async def read_file_handler(args: dict[str, Any]) -> ToolResult:
    """读取指定文件内容，支持 offset/limit 分页。"""
    file_path: str = args.get("file_path", "")
    if not file_path:
        return ToolResult.fail("file_path is required")

    file_path = os.path.expanduser(file_path)
    if not os.path.isabs(file_path):
        file_path = os.path.abspath(file_path)

    if not os.path.isfile(file_path):
        return ToolResult.fail(f"File not found: {file_path}")

    try:
        with open(file_path, "r", encoding="utf-8", errors="replace") as f:
            all_lines = f.readlines()
    except OSError as e:
        return ToolResult.fail(f"Cannot read file: {e}")

    total_lines = len(all_lines)
    offset = max(0, (args.get("offset") or 1) - 1)  # 1-indexed -> 0-indexed
    limit = args.get("limit") or total_lines

    selected = all_lines[offset: offset + limit]
    content = "".join(selected)

    if len(content) > MAX_OUTPUT_CHARS:
        half = MAX_OUTPUT_CHARS // 2
        content = content[:half] + "\n\n... [truncated] ...\n\n" + content[-half:]

    return ToolResult.ok(ReadFileData(
        content=content,
        file_path=file_path,
        total_lines=total_lines,
        lines_read=len(selected),
        offset=offset,
    ))


def render_read_file_result(result: ToolResult) -> str:
    """将 ReadFile 结果格式化为带行号的文本，供 LLM 阅读。"""
    if not result.success:
        return f"Error reading file: {result.error}"

    data: ReadFileData = result.data
    lines = data.content.split("\n")

    # 如果末尾是空行（来自尾部 \n），去掉以避免多余空行号
    if lines and lines[-1] == "":
        lines = lines[:-1]

    numbered = [
        f"{str(i + 1 + data.offset).rjust(6)}|{line}"
        for i, line in enumerate(lines)
    ]
    output = "\n".join(numbered)

    if data.total_lines > data.lines_read:
        output += (
            f"\n\n[Showing lines {data.offset + 1}-"
            f"{data.offset + data.lines_read} of {data.total_lines}]"
        )

    return output
